### 2. IndexedDB JavaScript Interop

Create `wwwroot/js/indexedDb.js`:

```javascript
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbFunctions = {
    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(JSON.parse(item));
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },
    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },
    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },
    getItemsByIndex: async function (storeName, indexName, value) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },
    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },
    getUnsyncedInspections: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.getAll();
            request.onsuccess = () => {
                const unsynced = (request.result || []).filter(i => !i.isSynced);
                resolve(JSON.stringify(unsynced));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    }
};
```

### 3. Client Services

**Services/IndexedDbService.cs**:
```csharp
using Microsoft.JSInterop;
using System.Text.Json;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions _jsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task PutAsync<T>(string storeName, T item)
    {
        var json = JsonSerializer.Serialize(item, _jsonOptions);
        await _js.InvokeVoidAsync("indexedDbFunctions.putItem", storeName, json);
    }

    public async Task<T?> GetAsync<T>(string storeName, string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbFunctions.getItem", storeName, id);
        return json is null ? default : JsonSerializer.Deserialize<T>(json, _jsonOptions);
    }

    public async Task<List<T>> GetAllAsync<T>(string storeName)
    {
        var json = await _js.InvokeAsync<string>("indexedDbFunctions.getAllItems", storeName);
        return JsonSerializer.Deserialize<List<T>>(json, _jsonOptions) ?? new();
    }

    public async Task<List<T>> GetByIndexAsync<T>(string storeName, string indexName, object value)
    {
        var json = await _js.InvokeAsync<string>("indexedDbFunctions.getItemsByIndex", storeName, indexName, value);
        return JsonSerializer.Deserialize<List<T>>(json, _jsonOptions) ?? new();
    }

    public async Task DeleteAsync(string storeName, string id)
    {
        await _js.InvokeVoidAsync("indexedDbFunctions.deleteItem", storeName, id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbFunctions.getUnsyncedInspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, _jsonOptions) ?? new();
    }
}
```

**Services/ConnectivityService.cs**:
```csharp
using Microsoft.JSInterop;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _selfRef;
    public bool IsOnline { get; private set; } = true;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        _selfRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
        await _js.InvokeVoidAsync("eval", $@"
            window.addEventListener('online', () => DotNet.invokeMethodAsync('SiteInspector.Client', 'OnConnectivityChanged', true));
            window.addEventListener('offline', () => DotNet.invokeMethodAsync('SiteInspector.Client', 'OnConnectivityChanged', false));
        ");
    }

    [JSInvokable("OnConnectivityChanged")]
    public static void HandleConnectivityChanged(bool isOnline)
    {
        // This is a static method for JS interop; instance-level handling done via the event
    }

    public async ValueTask DisposeAsync()
    {
        _selfRef?.Dispose();
    }
}
```

Actually, let me simplify the connectivity approach. Use a simpler JS interop:

Create `wwwroot/js/connectivity.js`:
```javascript
window.connectivityFunctions = {
    isOnline: function () {
        return navigator.onLine;
    },
    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('HandleOnline'));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('HandleOffline'));
    }
};
```

Then the service:
```csharp
using Microsoft.JSInterop;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _selfRef;
    public bool IsOnline { get; private set; } = true;
    public event Func<bool, Task>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        _selfRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityFunctions.isOnline");
        await _js.InvokeVoidAsync("connectivityFunctions.registerOnlineHandler", _selfRef);
    }

    [JSInvokable]
    public async Task HandleOnline()
    {
        IsOnline = true;
        if (OnConnectivityChanged != null) await OnConnectivityChanged.Invoke(true);
    }

    [JSInvokable]
    public async Task HandleOffline()
    {
        IsOnline = false;
        if (OnConnectivityChanged != null) await OnConnectivityChanged.Invoke(false);
    }

    public async ValueTask DisposeAsync() => _selfRef?.Dispose();
}
```

**Services/SyncService.cs**:
```csharp
using System.Net.Http.Json;

public class SyncService
{
    private readonly HttpClient _http;
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    public bool IsSyncing { get; private set; }
    public event Action? OnSyncStatusChanged;
    public DateTime? LastSyncTime { get; private set; }

    public SyncService(HttpClient http, IndexedDbService db, ConnectivityService connectivity)
    {
        _http = http;
        _db = db;
        _connectivity = connectivity;
    }

    public async Task<SyncResult?> SyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return null;

        try
        {
            IsSyncing = true;
            OnSyncStatusChanged?.Invoke();

            var unsyncedInspections = await _db.GetUnsyncedInspectionsAsync();
            var sites = await _db.GetAllAsync<ConstructionSite>("sites");

            var payload = new SyncPayload
            {
                Sites = sites,
                Inspections = unsyncedInspections
            };

            var response = await _http.PostAsJsonAsync("api/sync", payload);
            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadFromJsonAsync<SyncResult>();

                // Mark inspections as synced
                foreach (var inspection in unsyncedInspections)
                {
                    inspection.IsSynced = true;
                    inspection.SyncedAt = DateTime.UtcNow;
                    await _db.PutAsync("inspections", inspection);
                }

                LastSyncTime = DateTime.UtcNow;
                return result;
            }
        }
        catch (Exception)
        {
            // Sync failed — will retry later
        }
        finally
        {
            IsSyncing = false;
            OnSyncStatusChanged?.Invoke();
        }

        return null;
    }
}
```

