**Pages/Index.razor** — Home / Sites List:
```razor
@page "/"
@inject IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <div class="connectivity-badge @(isOnline ? "online" : "offline")">
        @(isOnline ? "Online" : "Offline")
    </div>
</div>

<div class="action-bar">
    <button class="btn-primary" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (showAddSite)
{
    <div class="card add-site-card">
        <h3>New Construction Site</h3>
        <div class="form-group">
            <label>Site Name</label>
            <input @bind="newSite.Name" placeholder="e.g., Building A — Phase 2" class="form-input" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input @bind="newSite.Address" placeholder="123 Main St" class="form-input" />
        </div>
        <div class="button-row">
            <button class="btn-primary" @onclick="SaveSite">Save</button>
            <button class="btn-secondary" @onclick="() => showAddSite = false">Cancel</button>
        </div>
    </div>
}

@if (sites.Count == 0 && !loading)
{
    <div class="empty-state">
        <p>📋 No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}

@foreach (var site in sites)
{
    <div class="card site-card" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
        <div class="site-name">@site.Name</div>
        <div class="site-address">📍 @site.Address</div>
        <div class="site-meta">Added @site.CreatedAt.ToString("MMM d, yyyy")</div>
    </div>
}

@code {
    private List<ConstructionSite> sites = new();
    private ConstructionSite newSite = new();
    private bool showAddSite;
    private bool loading = true;
    private bool isOnline = true;
    [CascadingParameter] public bool? IsOnline { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadSites();
        loading = false;
    }

    protected override void OnParametersSet()
    {
        isOnline = IsOnline ?? true;
    }

    private async Task LoadSites()
    {
        sites = await Db.GetAllAsync<ConstructionSite>("sites");
        sites = sites.OrderByDescending(s => s.CreatedAt).ToList();
    }

    private void ShowAddSite()
    {
        newSite = new ConstructionSite();
        showAddSite = true;
    }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(newSite.Name)) return;
        await Db.PutAsync("sites", newSite);
        showAddSite = false;
        await LoadSites();
    }
}
```

