            await file.OpenReadStream(10 * 1024 * 1024).ReadAsync(buffer);

            inspection.Photos.Add(new InspectionPhoto
            {
                FileName = file.Name,
                ContentType = file.ContentType,
                Base64Data = Convert.ToBase64String(buffer),
                CapturedAt = DateTime.UtcNow
            });
