Actually, let me simplify the connectivity approach. Use a simpler JS interop:

Create `wwwroot/js/connectivity.js`:
```javascript
window.connectivityFunctions = {
    isOnline: function () {
        return navigator.onLine;
    },
    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('HandleOnline'));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('HandleOffline'));
    }
};
```

Then the service:
```csharp
using Microsoft.JSInterop;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _selfRef;
    public bool IsOnline { get; private set; } = true;
    public event Func<bool, Task>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        _selfRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityFunctions.isOnline");
        await _js.InvokeVoidAsync("connectivityFunctions.registerOnlineHandler", _selfRef);
    }

    [JSInvokable]
    public async Task HandleOnline()
    {
        IsOnline = true;
        if (OnConnectivityChanged != null) await OnConnectivityChanged.Invoke(true);
    }

    [JSInvokable]
    public async Task HandleOffline()
    {
        IsOnline = false;
        if (OnConnectivityChanged != null) await OnConnectivityChanged.Invoke(false);
    }

    public async ValueTask DisposeAsync() => _selfRef?.Dispose();
}
```

**Services/SyncService.cs**:
```csharp
using System.Net.Http.Json;

public class SyncService
{
    private readonly HttpClient _http;
    private readonly IndexedDbService _db;
    private readonly ConnectivityService _connectivity;
    public bool IsSyncing { get; private set; }
    public event Action? OnSyncStatusChanged;
    public DateTime? LastSyncTime { get; private set; }

    public SyncService(HttpClient http, IndexedDbService db, ConnectivityService connectivity)
    {
        _http = http;
        _db = db;
        _connectivity = connectivity;
    }

    public async Task<SyncResult?> SyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return null;

        try
        {
            IsSyncing = true;
            OnSyncStatusChanged?.Invoke();

            var unsyncedInspections = await _db.GetUnsyncedInspectionsAsync();
            var sites = await _db.GetAllAsync<ConstructionSite>("sites");

            var payload = new SyncPayload
            {
                Sites = sites,
                Inspections = unsyncedInspections
            };

            var response = await _http.PostAsJsonAsync("api/sync", payload);
            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadFromJsonAsync<SyncResult>();

                // Mark inspections as synced
                foreach (var inspection in unsyncedInspections)
                {
                    inspection.IsSynced = true;
                    inspection.SyncedAt = DateTime.UtcNow;
                    await _db.PutAsync("inspections", inspection);
                }

                LastSyncTime = DateTime.UtcNow;
                return result;
            }
        }
        catch (Exception)
        {
            // Sync failed — will retry later
        }
        finally
        {
            IsSyncing = false;
            OnSyncStatusChanged?.Invoke();
        }

        return null;
    }
}
```

