**Server/Controllers/SyncController.cs**:
```csharp
[ApiController]
[Route("api/[controller]")]
public class SyncController : ControllerBase
{
    private static readonly List<ConstructionSite> _sites = new();
    private static readonly List<Inspection> _inspections = new();

    [HttpPost]
    public ActionResult<SyncResult> Sync([FromBody] SyncPayload payload)
    {
        // Merge sites
        foreach (var site in payload.Sites)
        {
            if (!_sites.Any(s => s.Id == site.Id))
                _sites.Add(site);
        }

        // Merge inspections
        foreach (var inspection in payload.Inspections)
        {
            var existing = _inspections.FindIndex(i => i.Id == inspection.Id);
            if (existing >= 0)
                _inspections[existing] = inspection;
            else
                _inspections.Add(inspection);
        }

        return Ok(new SyncResult
        {
            Success = true,
            SitesReceived = payload.Sites.Count,
            InspectionsReceived = payload.Inspections.Count,
            SyncedAt = DateTime.UtcNow
        });
    }
}
```

