+                }
+
+                LastSyncTime = DateTime.UtcNow;
+                return result;
+            }
+        }
+        catch (Exception)
+        {
+            // Sync failed — will retry when connectivity returns
+        }
+        finally
+        {
+            IsSyncing = false;
+            OnSyncStatusChanged?.Invoke();
+        }
+
+        return null;
+    }
+}
