        <input @bind="inspection.InspectorName" placeholder="Your name" class="form-input" />
    </div>

    <div class="checklist-section">
        <h2>Safety Checklist</h2>
        <div class="category-filter">
            <button class="@(selectedCategory == null ? "filter-active" : "filter-btn")"
                    @onclick="() => selectedCategory = null">All</button>
            @foreach (var cat in categories)
            {
                <button class="@(selectedCategory == cat ? "filter-active" : "filter-btn")"
                        @onclick="() => SelectCategory(cat)">@cat</button>
            }
        </div>

        @foreach (var item in filteredItems)
        {
            <div class="checklist-item @item.Status.ToString().ToLower()">
                <div class="checklist-description">
                    <span class="checklist-category-tag">@item.Category</span>
                    @item.Description
                </div>
                <div class="checklist-actions">
                    <button class="status-btn pass @(item.Status == ChecklistStatus.Pass ? "active" : "")"
                            @onclick="() => SetStatus(item, ChecklistStatus.Pass)">✓</button>
                    <button class="status-btn fail @(item.Status == ChecklistStatus.Fail ? "active" : "")"
                            @onclick="() => SetStatus(item, ChecklistStatus.Fail)">✗</button>
                    <button class="status-btn na @(item.Status == ChecklistStatus.NotApplicable ? "active" : "")"
                            @onclick="() => SetStatus(item, ChecklistStatus.NotApplicable)">N/A</button>
                </div>
                @if (item.Status == ChecklistStatus.Fail)
                {
                    <div class="checklist-note">
                        <input @bind="item.Notes" placeholder="Add note about failure..." class="form-input" />
                    </div>
                }
            </div>
        }
    </div>

    <div class="form-group">
        <h2>General Notes</h2>
        <textarea @bind="inspection.Notes" placeholder="Additional observations..." class="form-textarea" rows="4"></textarea>
    </div>

    <div class="photos-section">
        <h2>Photos (@inspection.Photos.Count)</h2>
        <label class="btn-secondary photo-btn">
            📷 Add Photo
            <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" style="display:none" />
        </label>

        <div class="photo-grid">
            @foreach (var photo in inspection.Photos)
            {
                <div class="photo-thumb">
                    <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                    <input @bind="photo.Caption" placeholder="Caption..." class="photo-caption-input" />
                    <button class="photo-remove" @onclick="() => RemovePhoto(photo)">✕</button>
                </div>
            }
        </div>
    </div>

    <div class="form-group">
        <div class="progress-summary">
            @{
                var completed = inspection.ChecklistItems.Count(c => c.Status != ChecklistStatus.NotChecked);
                var total = inspection.ChecklistItems.Count;
                var pct = total > 0 ? (int)(completed * 100.0 / total) : 0;
            }
            <div class="progress-bar">
                <div class="progress-fill" style="width: @(pct)%"></div>
            </div>
            <span>@completed / @total items checked (@pct%)</span>
        </div>
    </div>

    <div class="button-row sticky-bottom">
        <button class="btn-primary btn-large" @onclick="SaveInspection" disabled="@saving">
            @(saving ? "Saving..." : "💾 Save Inspection")
        </button>
    </div>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";
    private Inspection inspection = new();
    private string? selectedCategory;
    private List<string> categories = new();
    private bool saving;

    private List<ChecklistItem> filteredItems => selectedCategory == null
        ? inspection.ChecklistItems
        : inspection.ChecklistItems.Where(c => c.Category == selectedCategory).ToList();

    protected override void OnInitialized()
    {
        inspection.SiteId = SiteId;
        inspection.ChecklistItems = ChecklistTemplateService.GetDefaultChecklist();
        categories = inspection.ChecklistItems.Select(c => c.Category).Distinct().ToList();
    }

    private void SelectCategory(string cat)
    {
        selectedCategory = cat;
    }

    private void SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = item.Status == status ? ChecklistStatus.NotChecked : status;
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue;

            var buffer = new byte[file.Size];
            await file.OpenReadStream(10 * 1024 * 1024).ReadAsync(buffer);

            inspection.Photos.Add(new InspectionPhoto
            {
                FileName = file.Name,
                ContentType = file.ContentType,
                Base64Data = Convert.ToBase64String(buffer),
                CapturedAt = DateTime.UtcNow
            });
        }
    }

    private void RemovePhoto(InspectionPhoto photo)
    {
        inspection.Photos.Remove(photo);
    }

    private async Task SaveInspection()
    {
        if (string.IsNullOrWhiteSpace(inspection.InspectorName)) return;
        saving = true;
        try
        {
            inspection.InspectedAt = DateTime.UtcNow;
            await Db.PutAsync("inspections", inspection);
            Nav.NavigateTo($"site/{SiteId}");
        }
        finally
        {
            saving = false;
        }
    }

    private void GoBack()
    {
        Nav.NavigateTo($"site/{SiteId}");
    }
}

