@inherits LayoutComponentBase
@inject SiteInspector.Client.Services.ConnectivityService Connectivity
@inject SiteInspector.Client.Services.SyncService Sync

<div class="app-container">
    <main class="main-content">
        @Body
    </main>

    <div class="status-bar">
        <span class="connectivity @(Connectivity.IsOnline ? "online" : "offline")">
            @(Connectivity.IsOnline ? "🟢 Online" : "🔴 Offline")
        </span>
        @if (Sync.IsSyncing)
        {
            <span class="syncing">🔄 Syncing...</span>
        }
        else if (Sync.LastSyncTime.HasValue)
        {
            <span class="last-sync">Last sync: @Sync.LastSyncTime.Value.ToString("h:mm tt")</span>
        }
        <button class="btn-sync" @onclick="DoSync" disabled="@(!Connectivity.IsOnline || Sync.IsSyncing)">
            Sync Now
        </button>
