}

.connectivity {
    font-size: 0.85rem;
    font-weight: 600;
}

.connectivity.online { color: var(--success); }
.connectivity.offline { color: var(--danger); }

.syncing {
    font-size: 0.85rem;
    color: var(--primary);
}

.last-sync {
    font-size: 0.8rem;
    color: var(--gray-500);
}

.btn-sync {
    margin-left: auto;
    background: var(--primary);
    color: white;
    border: none;
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    min-height: 36px;
    touch-action: manipulation;
}

.btn-sync:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Sticky Bottom */
.sticky-bottom {
    position: sticky;
    bottom: 68px;
    background: var(--gray-50);
    padding: 16px 0;
    z-index: 10;
}

/* Loading */
.loading-progress {
    position: relative;
    display: block;
    width: 8rem;
    height: 8rem;
    margin: 20vh auto 1rem auto;
}

.loading-progress circle {
    fill: none;
    stroke: #e0e0e0;
    stroke-width: 0.6rem;
    transform-origin: 50% 50%;
    transform: rotate(-90deg);
}

.loading-progress circle:last-child {
    stroke: var(--primary);
    stroke-dasharray: calc(3.14 * 8rem);
    stroke-dashoffset: calc(3.14 * 8rem);
    animation: loading-spin 2s linear infinite;
}

@keyframes loading-spin {
    0% { stroke-dashoffset: calc(3.14 * 8rem); transform: rotate(-90deg); }
    50% { stroke-dashoffset: 0; transform: rotate(-90deg); }
    100% { stroke-dashoffset: calc(-3.14 * 8rem); transform: rotate(-90deg); }
